from agno import MultimodalAgent
from vex import verify

@verify(
    assertions=[
        "image_contains_valid_signature",
        "audio_transcription_accuracy > 95%",
        "no_PII_extracted_from_multimodal_input"
    ]
)
def process_citizen_media(agent: MultimodalAgent, media_file):
    analysis = agent.run(media_file)
    return {
        'validity': analysis['signature_valid'],
        'transcription': analysis['text'],
        'confidence': analysis['confidence']
    }

from agno import Team
from vex import verify

@verify(
    assertions=[
        "all_subagents_agree_on_final_decision",
        "coordination_log_complete",
        "risk_score_below_threshold"
    ],
    output_schema="gov_decision_schema.json"
)
def coordinated_threat_assessment(team: Team, intel_data):
    results = team.run(intel_data)
    final_decision = team.resolve_conflicts(results)
    return {
        'decision': final_decision,
        'subagent_votes': results,
        'explanation': team.explain_decision()
    }
